const now=()=>new Date().toISOString();
const clip=(v,n=3900)=>String(v??"").slice(0,n);
const uid=p=>`${p}_${crypto.randomUUID().slice(0,8)}`;
const clean=p=>String(p||"").trim().replace(/^\/+/,"");
const safe=p=>{const x=clean(p);return x&&!x.includes("..")&&x.length<180&&/^[\w./-]+$/.test(x)?x:null};
const out=(data,status=200)=>new Response(JSON.stringify(data,null,2),{status,headers:H});
function parse(update){const m=update?.message||update?.edited_message;if(!m)return null;const text=String(m.text||"").trim();let command=null,args="";if(text.startsWith("/")){const i=text.indexOf(" ");command=(i<0?text:text.slice(0,i)).replace(/@\w+$/,"").trim().toLowerCase();args=i<0?"":text.slice(i+1).trim()}return{chatId:m.chat?.id,userId:m.from?.id,text,command,args}}
async function kvText(env,key){return String(await env.MINISKYNET_KV.get(key)||"").trim()}
async function kvGet(env,key,fallback){const raw=await env.MINISKYNET_KV.get(key);if(!raw)return fallback;try{return JSON.parse(raw)}catch{return fallback}}
async function kvPut(env,key,value){await env.MINISKYNET_KV.put(key,JSON.stringify(value,null,2))}
async function arr(env,key){const v=await kvGet(env,key,{[key]:[]});return Array.isArray(v?.[key])?v[key]:[]}
async function saveArr(env,key,items,limit=100){await kvPut(env,key,{[key]:items.slice(-limit)})}
async function cfg(env){return{telegram:String(env.TELEGRAM_BOT_TOKEN||"").trim()||await kvText(env,"config:TELEGRAM_BOT_TOKEN"),owner:String(env.TELEGRAM_ALLOWED_USER_ID||"").trim()||await kvText(env,"config:TELEGRAM_ALLOWED_USER_ID"),openrouter:String(env.OPENROUTER_API_KEY||"").trim()||await kvText(env,"config:OPENROUTER_API_KEY"),gh:String(env.GITHUB_TOKEN||"").trim()||await kvText(env,"config:GITHUB_TOKEN"),repo:String(env.GITHUB_REPO||"").trim()||await kvText(env,"config:GITHUB_REPO")||DEFAULT_REPO,branch:String(env.GITHUB_BRANCH||"").trim()||await kvText(env,"config:GITHUB_BRANCH")||DEFAULT_BRANCH,worker:String(env.WORKER_URL||"").trim()||await kvText(env,"config:WORKER_URL")||DEFAULT_WORKER_URL,model:String(env.OPENROUTER_MODEL_CHEAP||"").trim()||await kvText(env,"config:OPENROUTER_MODEL_CHEAP")||"openai/gpt-4o-mini"}}
function ownerOk(c,userId){return!c.owner||String(userId||"")===String(c.owner)}
async function tg(c,method,body){if(!c.telegram)throw new Error("TELEGRAM_BOT_TOKEN missing");const r=await fetch(`https://api.telegram.org/bot${c.telegram}/${method}`,{method:"POST",headers:{"content-type":"application/json"},body:JSON.stringify(body)});return r.json().catch(()=>({}))}
async function send(c,chatId,text){if(Array.isArray(c?.__capture)){c.__capture.push(clip(text));return{ok:true,captured:true}}if(chatId)await tg(c,"sendMessage",{chat_id:chatId,text:clip(text)})}
const b64d=x=>new TextDecoder("utf-8").decode(Uint8Array.from(atob(String(x||"").replace(/\n/g,"")),ch=>ch.charCodeAt(0)));
function b64e(x){const b=new TextEncoder().encode(String(x||""));let s="";for(let i=0;i<b.length;i+=0x8000)s+=String.fromCharCode(...b.slice(i,i+0x8000));return btoa(s)}
const pathUrl=p=>clean(p).split("/").map(encodeURIComponent).join("/");
async function readFile(c,path){const p=safe(path);if(!p)throw new Error("unsafe path");const headers={accept:"application/vnd.github+json","user-agent":"MiniSkynet-v517"};if(c.gh)headers.authorization=`Bearer ${c.gh}`;const r=await fetch(`https://api.github.com/repos/${c.repo}/contents/${pathUrl(p)}?ref=${encodeURIComponent(c.branch)}`,{headers});const d=await r.json().catch(()=>({}));if(!r.ok)throw new Error(`GitHub ${r.status}: ${d.message||"request failed"}`);if(Array.isArray(d)||!d.content)throw new Error("not a text file");return{path:p,sha:d.sha||"",size:d.size||0,content:b64d(d.content)}}
async function writeFile(c,path,sha,content,message){if(!c.gh)throw new Error("GITHUB_TOKEN missing");const p=safe(path);if(!p)throw new Error("unsafe path");if(p==="cloudflare/wrangler.toml")throw new Error("wrangler.toml write blocked by capability registry");const r=await fetch(`https://api.github.com/repos/${c.repo}/contents/${pathUrl(p)}`,{method:"PUT",headers:{accept:"application/vnd.github+json","content-type":"application/json","user-agent":"MiniSkynet-v517",authorization:`Bearer ${c.gh}`},body:JSON.stringify({message,content:b64e(content),sha,branch:c.branch})});const d=await r.json().catch(()=>({}));if(!r.ok)throw new Error(`GitHub write ${r.status}: ${d.message||"request failed"}`);return{commit_sha:d?.commit?.sha||"",content_sha:d?.content?.sha||""}}
async function deleteRepoFile(c,path,sha,message){if(!c.gh)throw new Error("GITHUB_TOKEN missing");const p=safe(path);if(!p)throw new Error("unsafe path");if(p==="cloudflare/wrangler.toml")throw new Error("wrangler.toml delete blocked");const r=await fetch(`https://api.github.com/repos/${c.repo}/contents/${pathUrl(p)}`,{method:"DELETE",headers:{accept:"application/vnd.github+json","content-type":"application/json","user-agent":"MiniSkynet-v531",authorization:`Bearer ${c.gh}`},body:JSON.stringify({message,sha,branch:c.branch})});const d=await r.json().catch(()=>({}));if(!r.ok)throw new Error(`GitHub delete ${r.status}: ${d.message||"request failed"}`);return{commit_sha:d?.commit?.sha||""}}

function mainFromWrangler(s){const m=String(s||"").match(/^main\s*=\s*["']([^"']+)["']/m);if(!m)return null;const rel=clean(m[1]);return rel.startsWith("cloudflare/")?rel:`cloudflare/${rel}`}
