function capPolicy(v){return CAPABILITY_RISK_LEVELS[v?.policy]||CAPABILITY_RISK_LEVELS.forbidden}
function capPolicyLines(){return Object.entries(CAPABILITY_RISK_LEVELS).map(([k,v])=>`- ${v.label}: auto_propose=${v.auto_propose_allowed?"yes":"no"}, auto_apply=${v.auto_apply_allowed?"yes":"no"}, confirm=${v.human_confirm_required?"yes":"no"}, writes=${v.writes_allowed===true?"yes":v.writes_allowed||"no"}, verify=${v.verify}`)}
