function capLinesV2(){return Object.entries(CAPABILITY_REGISTRY).map(([k,v])=>[`- ${k}: ${v.status}`,`  risk=${v.risk}`,`  allowed_paths=${(v.allowed_paths||[]).join(",")||"—"}`,`  allowed_patterns=${(v.allowed_patterns||[]).join(",")||"—"}`,`  protected=${(v.protected_paths||[]).join(",")||"—"}`,`  max_files=${v.max_files||"—"}`,`  writes_allowed=${v.writes_allowed===true?"yes":"no"}`,`  deletes_allowed=${v.deletes_allowed===true?"yes":v.deletes_allowed==="guarded"?"guarded":"no"}`,`  manifest_required=${v.requires_manifest===true?"yes":"no"}`,`  manual_confirm=${v.manual_confirm===true?"yes":"no"}`,`  rollback_required=${v.rollback_required===true?"yes":"no"}`].join("\n"))}
function capLinesV3(){return Object.entries(CAPABILITY_REGISTRY).map(([k,v])=>{const p=capPolicy(v);return[`- ${k}: ${v.status}`,`  level=${p.label}`,`  legacy_risk=${v.risk}`,`  auto_propose=${v.auto_propose_allowed===true?"yes":"no"}`,`  auto_apply=${v.auto_apply_allowed===true?"yes":"no"}`,`  human_confirm=${v.manual_confirm===true?"yes":"no"}`,`  source_verify=${v.source_verify?"yes":"no"}`,`  live_verify=${v.live_verify?"yes":"no"}`,`  rollback=${v.rollback?"yes":"no"}`,`  writes=${v.writes_allowed===true?"yes":"no"}`,`  deletes=${v.deletes_allowed===true?"yes":v.deletes_allowed==="guarded"?"guarded":"no"}`,`  manifest=${v.requires_manifest===true?"yes":"no"}`,`  notes=${v.notes||p.notes}`].join("\n")})}
function registryText(args=""){const mode=String(args||"").trim().toLowerCase();if(mode==="v3")return["🧩 Capability Registry v3","risk policy levels:",...capPolicyLines(),"capabilities:",...capLinesV3(),"future autonomy policy:","- read-only: auto-propose allowed; auto-apply disabled ✅","- low-risk write: proposal allowed; apply_confirm remains required ✅","- medium supervised write: proposal allowed; live verify + rollback required ✅","- high guarded action: no auto-propose/auto-apply; manifest + exact confirm required ✅","- forbidden: blocked before parser ✅","low-risk auto-apply policy v1:",...autoApplyPolicyLines(),"forbidden:",...FORBIDDEN_CAPABILITIES.map(x=>`- ${x}`)].join("\n");if(mode==="v2")return["🧩 Capability Registry v2","allowed capabilities:",...capLinesV2(),"multi-file guards:","- write/delete without manifest: blocked ✅","- wrangler.toml protected ✅","- active target protected ✅","- manual confirm required for cleanup_manifest_based_action ✅","- existing safe_command_add/rich_command_add/add_marker preserved ✅","forbidden:",...FORBIDDEN_CAPABILITIES.map(x=>`- ${x}`)].join("\n");return["🧩 Capability Registry v3","allowed:",...capLines(),"hint: /capabilities v3","forbidden:",...FORBIDDEN_CAPABILITIES.map(x=>`- ${x}`),"guard:","- forbidden tokens checked before parser ✅","- multi-file write/delete without manifest blocked ✅","- risk policy levels visible in /capabilities v3 ✅","patch planner: v1.1 regex syntax safety ✅","native live_pending_v2: auto-probe ✅","cost guard: active v1 ✅","project_map: dynamic v2 ✅","cleanup_scan: dynamic v2.1 ✅","cleanup_plan: read-only v1.1 compact ✅","cleanup_manifest: read-only v1.1 paged ✅","cleanup_manifest_save: KV snapshot v1 ✅","cleanup_delete_preview: read-only v1 ✅","cleanup_delete_prepare: KV job v1 ✅","cleanup_delete_job: read-only status v1 ✅","cleanup_delete_executor: guarded v1 ✅","cleanup_rollback_viewer: read-only v1 ✅","native_template_add: self-apply v2 ✅"].join("\n")}
function multiFilePathAllowed(path,cap){const p=String(path||"");if(!p)return false;if((cap.protected_paths||[]).includes(p))return false;if(p==="cloudflare/wrangler.toml")return false;return (cap.allowed_paths||[]).some(base=>p.startsWith(base))}
function multiFileSafetyCheck(op,c){if(!c)return{ok:false,reason:"missing capability record"};const paths=Array.isArray(op?.paths)?op.paths:[];const count=Number(op?.file_count||paths.length||0);const wantsWrite=!!(op?.write||op?.writes||op?.delete||op?.deletes);if(c.max_files&&count>c.max_files)return{ok:false,reason:`multi-file limit exceeded: ${count}/${c.max_files}`};if(paths.some(p=>!multiFilePathAllowed(p,c)))return{ok:false,reason:"multi-file path outside allowed patterns or protected path"};if(wantsWrite&&(c.writes_allowed!==true&&c.deletes_allowed!==true))return{ok:false,reason:"multi-file write/delete blocked by registry"};if(wantsWrite&&c.requires_manifest&&!op.manifest_id)return{ok:false,reason:"multi-file write/delete requires manifest"};if(wantsWrite&&c.manual_confirm&&!op.manual_confirm)return{ok:false,reason:"multi-file write/delete requires manual confirm"};return{ok:true}}

