function forbiddenRequest(req){const t=String(req||"").toLowerCase();const compact=t.replace(/[\s-]+/g,"_");for(const x of FORBIDDEN_CAPABILITIES){if(compact.includes(x))return{type:x,blocked:true,reason:`forbidden token detected: ${x}`}}if((t.includes("произволь")&&t.includes("js"))||(t.includes("произволь")&&t.includes("код")))return{type:B_JS,blocked:true,reason:`forbidden token detected: ${B_JS}`};if(t.includes("ручная правка")||t.includes("ручной код"))return{type:B_MANUAL,blocked:true,reason:`forbidden token detected: ${B_MANUAL}`};if(t.includes("внешний")&&t.includes("fetch"))return{type:B_EXT,blocked:true,reason:`forbidden token detected: ${B_EXT}`};return null}
