function buildCodeSymbolMapV1(src){
  const text=String(src||"");
  const rows=[];
  const seen=new Set();
  const push=x=>{
    x=String(x||"").replace(/[\r\n]+/g," ").replace(/\s+/g," ").trim();
    if(!x||seen.has(x))return;
    if(/token|secret|password|passwd|credential|private|authorization|bearer|https?:\/\//i.test(x))return;
    seen.add(x);
    rows.push(x);
  };
  for(const m of text.matchAll(/\bconst\s+([A-Za-z_$][\w$]*)\s*=/g)){
    push(`const ${m[1]} =`);
    if(rows.length>=100)break;
  }
  for(const m of text.matchAll(/\b(async\s+function|function)\s+([A-Za-z_$][\w$]*)\s*\(([^)]{0,160})\)/g)){
    const params=String(m[3]||"").replace(/=.*?(?=,|$)/g,"").slice(0,120);
    push(`${m[1]} ${m[2]}(${params})`);
    if(rows.length>=100)break;
  }
  if(/\bexport\s+default\s*\{/.test(text))push("export default {");
  return rows.slice(0,100).join("\n").slice(0,2500);
}
async function buildThinkCodeContextV1(c){
  try{
    const a=await activeTarget(c);
    const path=String(a?.file?.path||"");
    if(projectAuditSecretLikePath(path))return "unavailable: active file blocked";
    const map=buildCodeSymbolMapV1(a?.file?.content||"");
    return map||"unavailable: no symbols found";
  }catch(e){
    return "unavailable";
  }
}
function realSymbolCheckRequestedV1(text){
  return /\bREAL\s+SYMBOL\s+CHECK\b|реальн\w*\s+symbol|проверк\w*\s+символ/i.test(String(text||""));
}
function realSymbolCheckTextV1(userText,codeContext){
  const requested=[...String(userText||"").matchAll(/(?:^|\n)\s*[-•]\s*([A-Za-z_$][\w$]*)/g)].map(m=>m[1]);
  const wanted=requested.length?requested:["CMDS","handle","projectStateSnapshot","plannerDecisionV2","proposalDraftV1","humanOutputScheduledDecisionV1","humanBriefingV1","humanBriefingTextV1","kvGet","kvPut","arr","saveArr","ownerOk","writeFile","applyGateDecisionV2","forbiddenRequest"];
  const lines=["🧭 REAL SYMBOL CHECK","source: Code Symbol Map v1","mode: deterministic, no roadmap fallback",""];
  const ctx=String(codeContext||"");
  for(const name of wanted){
    const re=new RegExp(`(^|\\n)(const ${name} =|(?:async\\s+)?function ${name}\\([^\\n]*\\))`);
    const m=ctx.match(re);
    lines.push(`${name} → ${m?m[2]:"MISSING"}`);
  }
  lines.push("","Если есть MISSING — /think всё ещё не видит этот declaration в symbol map.");
  return lines.join("\n");
}
async function realSymbolCheckFromActiveFileV1(c,userText){
  let file;
  try{
    const a=await activeTarget(c);
    file=a.file;
    if(projectAuditSecretLikePath(file.path))return "🧭 REAL SYMBOL CHECK\nstate: BLOCKED\nreason: active file path is secret-like";
  }catch(e){
    return "🧭 REAL SYMBOL CHECK\nstate: unavailable\nreason: active target read failed";
  }
  const src=String(file.content||"");
  const requested=[...String(userText||"").matchAll(/(?:^|\n)\s*[-•]\s*([A-Za-z_$][\w$]*)/g)].map(m=>m[1]);
  const wanted=requested.length?requested:["CMDS","handle","projectStateSnapshot","plannerDecisionV2","proposalDraftV1","humanOutputScheduledDecisionV1","humanBriefingV1","humanBriefingTextV1","kvGet","kvPut","arr","saveArr","ownerOk","writeFile","applyGateDecisionV2","forbiddenRequest"];
  const esc=s=>String(s||"").replace(/[.*+?^${}()|[\]\\]/g,"\\$&");
  const decl=name=>{
    const n=esc(name);
    let m=src.match(new RegExp(`\\basync\\s+function\\s+${n}\\s*\\(([^)]{0,180})\\)`));
    if(m)return `async function ${name}(${String(m[1]||"").replace(/=.*?(?=,|$)/g,"").slice(0,120)})`;
    m=src.match(new RegExp(`\\bfunction\\s+${n}\\s*\\(([^)]{0,180})\\)`));
    if(m)return `function ${name}(${String(m[1]||"").replace(/=.*?(?=,|$)/g,"").slice(0,120)})`;
    m=src.match(new RegExp(`\\bconst\\s+${n}\\s*=`));
    if(m)return `const ${name} =`;
    return "MISSING";
  };
  const lines=["🧭 REAL SYMBOL CHECK","source: active runtime file full-source scan","mode: deterministic, no roadmap fallback, no model call","",`path: ${file.path}`,`sha: ${String(file.sha||"").slice(0,12)}`,""];
  for(const name of wanted)lines.push(`${name} → ${decl(name)}`);
  lines.push("","Если MISSING нет — /think получил code-reading режим нормально.");
  return lines.join("\n").slice(0,3900);
}
