  const r=await fetch("https://openrouter.ai/api/v1/chat/completions",{method:"POST",headers:{"content-type":"application/json",authorization:`Bearer ${c.openrouter}`},body:JSON.stringify({model:c.model,messages:[{role:"system",content:"Return strict JSON only. No markdown. No secrets."},{role:"user",content:prompt}],max_tokens:800,temperature:0.15})});
