  const cmd=llmIntentCleanCommandV1(x.mapped_command||x.command||"");
  const risk=String(x.risk||llmIntentRiskForCommandV1(cmd)||"answer_only").toLowerCase();
  const confidence=Math.max(0,Math.min(0.99,Number(x.confidence||0)));
  const out={
    intent:clip(String(x.intent||"unknown"),80),
    target:clip(String(x.target||""),120),
    mapped_command:cmd,
    mapped_args:llmIntentCleanArgsV1(x.mapped_args||x.args||""),
    risk,
    confidence,
    needs_confirmation:!!x.needs_confirmation,
    clarification:clip(String(x.clarification||""),500),
    reply:clip(String(x.reply||""),900),
    plan:Array.isArray(x.plan)?x.plan.map(v=>clip(String(v),180)).slice(0,7):[],
    next_safe_step:clip(String(x.next_safe_step||""),240)
  };
  if(out.mapped_command&&!llmIntentAllowedCommandV1(out.mapped_command)){
    out.risk=llmIntentRiskForCommandV1(out.mapped_command);
    out.needs_confirmation=false;
  }
  if(out.intent==="set_preference"&&!out.mapped_command){
    out.mapped_command="/addtask";
    out.mapped_args=capabilityGapTaskTextV1("user_preferences",out.target||out.reply||"не показывать статус без просьбы");
    out.risk="state_changing";
    out.needs_confirmation=true;
    out.confidence=Math.max(out.confidence,0.82);
    if(!out.plan.length)out.plan=["создать безопасное хранилище пользовательских правил","применять правила в human output и intent brain","не менять поведение без подтверждения"];
  }
