export default{async fetch(request,env){const url=new URL(request.url);if(url.pathname==="/"||url.pathname==="/health")return out(health());if(url.pathname==="/telegram"&&request.method==="POST")return telegram(request,env);return out({ok:false,error:"not found",version:VERSION},404)},async scheduled(event,env,ctx){try{await safeAutonomyScheduledV1(event,env)}catch(e){console.log("safeAutonomyScheduledV1 error",String(e?.message||e))}}};
